-/// Codegen errors
-pub const CodegenError = error{
-    ExpectedModule,
-    UnsupportedExpression,
-    UnsupportedStatement,
-    UnsupportedTarget,
-    InvalidAssignment,
-    InvalidCompare,
-    EmptyTargets,
-    UnsupportedFunction,
-    UnsupportedCall,
-    UnsupportedMethod,
-    InvalidArguments,
-    MissingArgument,
